UPDATE hizmetler SET aciklama = 'Mesleğiniz, giyim kuşamınız ve toplumdaki statünüzü göz önünde bulundurarak sadece size özel kafa ve yüz şeklinize göre anatomik saç kesimi yapmaktayız. Her müşterimize özel kesim planı hazırlanır; yüz hatlarınızı en iyi yansıtan stil sizinle birlikte belirlenir.' WHERE ad = 'Saç Kesimi';

